from dataclasses import dataclass, field
from typing import Any
import time


@dataclass
class TraceStep:
    step: int
    thought: str
    action: str | None     # None on final-answer steps
    observation: str | None
    elapsed_ms: float


@dataclass
class AgentTrace:
    task: str
    steps: list[TraceStep] = field(default_factory=list)
    final_answer: str = ""
    total_ms: float = 0.0

    def record(self, thought: str, action: str | None,
               observation: str | None, elapsed_ms: float) -> None:
        self.steps.append(TraceStep(
            step=len(self.steps) + 1,
            thought=thought, action=action,
            observation=observation, elapsed_ms=elapsed_ms,
        ))

    def summarise(self) -> str:
        lines = [f"Task: {self.task}"]
        for s in self.steps:
            lines.append(f"  Step {s.step}: {s.thought[:60]}")
            if s.action:
                lines.append(f"    Action: {s.action}")
            if s.observation:
                lines.append(f"    Obs: {s.observation[:60]}")
        lines.append(f"Answer: {self.final_answer}")
        lines.append(f"Total: {self.total_ms:.0f}ms over {len(self.steps)} steps")
        return "\n".join(lines)

import anthropic


TASK_BUDGETS = {
    "simple":  2_000,   # factual lookup, arithmetic
    "medium":  6_000,   # multi-step reasoning, code review
    "complex": 15_000,  # proofs, long planning, adversarial checks
}


def classify_task_complexity(task: str) -> str:
    """Heuristic: key words that suggest deeper reasoning needs."""
    task_lower = task.lower()
    if any(w in task_lower for w in ["prove", "verify", "all possible", "optimal"]):
        return "complex"
    if any(w in task_lower for w in ["plan", "design", "compare", "debug"]):
        return "medium"
    return "simple"


def adaptive_call(client: anthropic.Anthropic, task: str) -> str:
    complexity = classify_task_complexity(task)
    budget = TASK_BUDGETS[complexity]
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=budget + 2000,   # answer headroom
        thinking={"type": "enabled", "budget_tokens": budget},
        messages=[{"role": "user", "content": task}],
    )
    for block in response.content:
        if block.type == "text":
            return block.text
    return ""
